-- Migration 3/13: canonical festival booking layer.

CREATE TYPE public.festival_application_status AS ENUM ('draft','submitted','under_review','waitlisted','shortlisted','offer_pending','withdrawn','rejected','expired','converted_to_contract');
CREATE TYPE public.festival_offer_status AS ENUM ('draft','sent','viewed','countered','accepted_pending_contract','declined','withdrawn','expired','converted_to_contract');
CREATE TYPE public.festival_contract_status AS ENUM ('draft','proposed','awaiting_band_signature','awaiting_organiser_signature','awaiting_signatures','active','amendment_required','cancelled','terminated','fulfilled','breached','expired');
CREATE TYPE public.festival_setlist_status AS ENUM ('draft','submitted','approved','changes_requested','locked','performed','cancelled');
CREATE TYPE public.festival_booking_side AS ENUM ('band','organiser');

CREATE OR REPLACE FUNCTION public.public_festival_editions_read()
RETURNS TABLE(id uuid, festival_id uuid, edition_number integer, edition_year integer, title text, description text, city_id uuid, venue_id uuid, start_at timestamptz, end_at timestamptz, expected_attendance integer, capacity integer, minimum_ticket_price_cents bigint, maximum_ticket_price_cents bigint, currency_code text, status public.festival_edition_status, public_metadata jsonb, announced_at timestamptz, on_sale_at timestamptz, live_at timestamptz, completed_at timestamptz)
LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $$
  SELECT e.id,e.festival_id,e.edition_number,e.edition_year,e.title,e.description,e.city_id,e.venue_id,e.start_at,e.end_at,e.expected_attendance,e.capacity,e.minimum_ticket_price_cents,e.maximum_ticket_price_cents,e.currency_code,e.status,e.public_metadata,e.announced_at,e.on_sale_at,e.live_at,e.completed_at
  FROM public.festival_editions e WHERE public.is_public_festival_edition_status(e.status)
$$;
REVOKE ALL ON FUNCTION public.public_festival_editions_read() FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.public_festival_editions_read() TO anon, authenticated;

ALTER TABLE IF EXISTS public.festival_stage_slots ADD COLUMN IF NOT EXISTS canonical_contract_id uuid;

CREATE TABLE public.festival_applications (
 id uuid PRIMARY KEY DEFAULT gen_random_uuid(), edition_id uuid NOT NULL REFERENCES public.festival_editions(id) ON DELETE CASCADE, band_id uuid NOT NULL REFERENCES public.bands(id) ON DELETE CASCADE, submitted_by_profile_id uuid REFERENCES public.profiles(id), status public.festival_application_status NOT NULL DEFAULT 'submitted', preferred_stage_types text[] DEFAULT '{}', preferred_slot_types text[] DEFAULT '{}', preferred_dates jsonb NOT NULL DEFAULT '[]', minimum_fee_cents bigint, requested_fee_cents bigint, currency_code text NOT NULL DEFAULT 'USD', requested_set_minutes integer, genre_fit_snapshot jsonb NOT NULL DEFAULT '{}', band_snapshot jsonb NOT NULL DEFAULT '{}', application_message text, organiser_notes text, eligibility_snapshot jsonb NOT NULL DEFAULT '{}', source text NOT NULL DEFAULT 'canonical', legacy_participant_id uuid, legacy_application_id uuid, withdrawal_reason text, rejection_reason text, expires_at timestamptz, submitted_at timestamptz DEFAULT now(), reviewed_at timestamptz, idempotency_key text, request_hash text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CHECK (coalesce(minimum_fee_cents,0) >= 0 AND coalesce(requested_fee_cents,0) >= 0), CHECK (requested_set_minutes IS NULL OR requested_set_minutes BETWEEN 5 AND 240), CHECK (currency_code ~ '^[A-Z]{3}$'));
CREATE UNIQUE INDEX festival_applications_one_active_idx ON public.festival_applications(edition_id, band_id) WHERE status IN ('draft','submitted','under_review','waitlisted','shortlisted','offer_pending');
CREATE UNIQUE INDEX festival_applications_idempotency_idx ON public.festival_applications(submitted_by_profile_id, idempotency_key) WHERE idempotency_key IS NOT NULL;

CREATE TABLE public.festival_contract_offers (
 id uuid PRIMARY KEY DEFAULT gen_random_uuid(), edition_id uuid NOT NULL REFERENCES public.festival_editions(id) ON DELETE CASCADE, application_id uuid REFERENCES public.festival_applications(id) ON DELETE SET NULL, band_id uuid NOT NULL REFERENCES public.bands(id) ON DELETE CASCADE, created_by_profile_id uuid REFERENCES public.profiles(id), status public.festival_offer_status NOT NULL DEFAULT 'sent', offer_revision integer NOT NULL DEFAULT 1, stage_slot_id uuid REFERENCES public.festival_stage_slots(id) ON DELETE SET NULL, proposed_stage_name text, proposed_slot_type text, proposed_start_at timestamptz, proposed_end_at timestamptz, guarantee_fee_cents bigint DEFAULT 0, deposit_cents bigint DEFAULT 0, performance_bonus_cents bigint DEFAULT 0, ticket_bonus_terms jsonb DEFAULT '{}', merch_share_percent numeric(5,2), travel_terms jsonb DEFAULT '{}', accommodation_terms jsonb DEFAULT '{}', hospitality_terms jsonb DEFAULT '{}', technical_terms jsonb DEFAULT '{}', exclusivity_terms jsonb DEFAULT '{}', cancellation_terms jsonb DEFAULT '{}', set_duration_minutes integer, currency_code text NOT NULL DEFAULT 'USD', message text, expires_at timestamptz, sent_at timestamptz DEFAULT now(), responded_at timestamptz, idempotency_key text, request_hash text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CHECK (guarantee_fee_cents >= 0 AND deposit_cents >= 0 AND performance_bonus_cents >= 0), CHECK (merch_share_percent IS NULL OR merch_share_percent BETWEEN 0 AND 100), CHECK (set_duration_minutes IS NULL OR set_duration_minutes BETWEEN 5 AND 240));
CREATE UNIQUE INDEX festival_offers_idempotency_idx ON public.festival_contract_offers(created_by_profile_id, idempotency_key) WHERE idempotency_key IS NOT NULL;

CREATE TABLE public.festival_offer_revisions (
 id uuid PRIMARY KEY DEFAULT gen_random_uuid(), offer_id uuid NOT NULL REFERENCES public.festival_contract_offers(id) ON DELETE CASCADE, revision_number integer NOT NULL, proposed_by_side public.festival_booking_side NOT NULL, proposed_by_profile_id uuid REFERENCES public.profiles(id), terms_snapshot jsonb NOT NULL, change_summary text, request_hash text NOT NULL, idempotency_key text, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(offer_id, revision_number), UNIQUE(offer_id, idempotency_key));

CREATE TABLE public.festival_contracts (
 id uuid PRIMARY KEY DEFAULT gen_random_uuid(), edition_id uuid NOT NULL REFERENCES public.festival_editions(id) ON DELETE CASCADE, application_id uuid REFERENCES public.festival_applications(id) ON DELETE SET NULL, offer_id uuid REFERENCES public.festival_contract_offers(id) ON DELETE SET NULL, accepted_offer_revision_id uuid REFERENCES public.festival_offer_revisions(id), band_id uuid NOT NULL REFERENCES public.bands(id), festival_id uuid REFERENCES public.festivals(id), stage_slot_id uuid REFERENCES public.festival_stage_slots(id), status public.festival_contract_status NOT NULL DEFAULT 'awaiting_signatures', contract_version integer NOT NULL DEFAULT 1, terms_snapshot jsonb NOT NULL DEFAULT '{}', band_signature_status text NOT NULL DEFAULT 'unsigned', organiser_signature_status text NOT NULL DEFAULT 'unsigned', band_signed_by_profile_id uuid REFERENCES public.profiles(id), organiser_signed_by_profile_id uuid REFERENCES public.profiles(id), band_signed_at timestamptz, organiser_signed_at timestamptz, activated_at timestamptz, cancelled_at timestamptz, terminated_at timestamptz, fulfilled_at timestamptz, cancellation_reason text, termination_reason text, legacy_participant_id uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CHECK (contract_version > 0), CHECK (status <> 'cancelled' OR cancellation_reason IS NOT NULL), CHECK (status <> 'terminated' OR termination_reason IS NOT NULL));
CREATE UNIQUE INDEX festival_contracts_one_active_idx ON public.festival_contracts(edition_id, band_id) WHERE status IN ('awaiting_band_signature','awaiting_organiser_signature','awaiting_signatures','active','amendment_required');
CREATE UNIQUE INDEX festival_contracts_stage_active_idx ON public.festival_contracts(stage_slot_id) WHERE stage_slot_id IS NOT NULL AND status IN ('awaiting_signatures','active');

CREATE TABLE public.festival_contract_signatures (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), contract_id uuid NOT NULL REFERENCES public.festival_contracts(id) ON DELETE CASCADE, contract_version integer NOT NULL, signing_side public.festival_booking_side NOT NULL, profile_id uuid REFERENCES public.profiles(id), terms_hash text NOT NULL, acknowledgement_snapshot jsonb NOT NULL DEFAULT '{}', idempotency_key text, signed_at timestamptz NOT NULL DEFAULT now(), UNIQUE(contract_id, contract_version, signing_side), UNIQUE(contract_id, signing_side, idempotency_key));

CREATE TABLE public.festival_contract_setlists (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), contract_id uuid NOT NULL REFERENCES public.festival_contracts(id) ON DELETE CASCADE, band_id uuid NOT NULL REFERENCES public.bands(id), edition_id uuid NOT NULL REFERENCES public.festival_editions(id), status public.festival_setlist_status NOT NULL DEFAULT 'draft', version integer NOT NULL DEFAULT 1, total_duration_seconds integer NOT NULL DEFAULT 0, maximum_duration_seconds integer NOT NULL, submitted_by_profile_id uuid REFERENCES public.profiles(id), submitted_at timestamptz, approved_at timestamptz, locked_at timestamptz, changes_requested_reason text, idempotency_key text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CHECK (total_duration_seconds >= 0), CHECK (maximum_duration_seconds BETWEEN 300 AND 14400));
CREATE UNIQUE INDEX festival_contract_setlists_current_idx ON public.festival_contract_setlists(contract_id, version);

CREATE TABLE public.festival_contract_setlist_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), setlist_id uuid NOT NULL REFERENCES public.festival_contract_setlists(id) ON DELETE CASCADE, position integer NOT NULL CHECK (position > 0), song_id uuid, planned_duration_seconds integer NOT NULL CHECK (planned_duration_seconds BETWEEN 30 AND 3600), performance_notes text, transition_notes text, is_encore boolean NOT NULL DEFAULT false, guest_profile_id uuid REFERENCES public.profiles(id), created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(setlist_id, position));

CREATE TABLE public.festival_application_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), application_id uuid REFERENCES public.festival_applications(id) ON DELETE CASCADE, from_state text, to_state text, actor_profile_id uuid, reason text, metadata jsonb NOT NULL DEFAULT '{}', idempotency_key text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE public.festival_contract_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), contract_id uuid REFERENCES public.festival_contracts(id) ON DELETE CASCADE, offer_id uuid REFERENCES public.festival_contract_offers(id) ON DELETE SET NULL, from_state text, to_state text, actor_profile_id uuid, reason text, metadata jsonb NOT NULL DEFAULT '{}', idempotency_key text, created_at timestamptz NOT NULL DEFAULT now());

GRANT SELECT ON public.festival_applications, public.festival_contract_offers, public.festival_offer_revisions, public.festival_contracts, public.festival_contract_signatures, public.festival_contract_setlists, public.festival_contract_setlist_items, public.festival_application_events, public.festival_contract_events TO authenticated;
GRANT ALL ON public.festival_applications, public.festival_contract_offers, public.festival_offer_revisions, public.festival_contracts, public.festival_contract_signatures, public.festival_contract_setlists, public.festival_contract_setlist_items, public.festival_application_events, public.festival_contract_events TO service_role;

CREATE OR REPLACE FUNCTION public.is_active_band_member(p_band_id uuid) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $$ SELECT EXISTS (SELECT 1 FROM public.band_members bm WHERE bm.band_id=p_band_id AND bm.user_id=auth.uid() AND coalesce(bm.member_status,'active')='active') $$;
CREATE OR REPLACE FUNCTION public.current_profile_id_safe() RETURNS uuid LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $$ SELECT public.current_profile_id() $$;
CREATE OR REPLACE FUNCTION public.festival_terms_hash(p_terms jsonb) RETURNS text LANGUAGE sql IMMUTABLE SET search_path=public AS $$ SELECT md5(coalesce(p_terms,'{}'::jsonb)::text) $$;

CREATE OR REPLACE FUNCTION public.submit_festival_application(p_edition_id uuid, p_band_id uuid, p_details jsonb DEFAULT '{}', p_idempotency_key text DEFAULT NULL) RETURNS public.festival_applications LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
DECLARE v_actor uuid := public.current_profile_id_safe(); v_edition public.festival_editions%ROWTYPE; v_existing public.festival_applications%ROWTYPE; v_app public.festival_applications%ROWTYPE; v_hash text := public.festival_terms_hash(coalesce(p_details,'{}'::jsonb));
BEGIN
 IF v_actor IS NULL OR NOT public.is_active_band_member(p_band_id) THEN RAISE EXCEPTION 'Not authorised to submit for this band'; END IF;
 SELECT * INTO v_edition FROM public.festival_editions WHERE id=p_edition_id; IF NOT FOUND OR v_edition.status NOT IN ('applications_open','booking','announced') THEN RAISE EXCEPTION 'Festival edition is not open for applications'; END IF;
 IF p_idempotency_key IS NOT NULL THEN SELECT * INTO v_existing FROM public.festival_applications WHERE submitted_by_profile_id=v_actor AND idempotency_key=p_idempotency_key; IF FOUND THEN IF v_existing.request_hash<>v_hash THEN RAISE EXCEPTION 'Idempotency key reused with different application'; END IF; RETURN v_existing; END IF; END IF;
 INSERT INTO public.festival_applications(edition_id,band_id,submitted_by_profile_id,preferred_stage_types,preferred_slot_types,preferred_dates,minimum_fee_cents,requested_fee_cents,currency_code,requested_set_minutes,application_message,eligibility_snapshot,band_snapshot,idempotency_key,request_hash)
 VALUES(p_edition_id,p_band_id,v_actor,coalesce(ARRAY(SELECT jsonb_array_elements_text(p_details->'preferred_stage_types')),'{}'),coalesce(ARRAY(SELECT jsonb_array_elements_text(p_details->'preferred_slot_types')),'{}'),coalesce(p_details->'preferred_dates','[]'),(p_details->>'minimum_fee_cents')::bigint,(p_details->>'requested_fee_cents')::bigint,coalesce(p_details->>'currency_code','USD'),(p_details->>'requested_set_minutes')::integer,p_details->>'application_message',jsonb_build_object('outcome','eligible','warnings','[]'::jsonb,'rule_config_version','festival-booking-v1'),(SELECT to_jsonb(b) FROM public.bands b WHERE b.id=p_band_id),p_idempotency_key,v_hash) RETURNING * INTO v_app;
 INSERT INTO public.festival_application_events(application_id,to_state,actor_profile_id,metadata,idempotency_key) VALUES(v_app.id,v_app.status::text,v_actor,jsonb_build_object('event','submitted'),p_idempotency_key); RETURN v_app;
END $$;

CREATE OR REPLACE FUNCTION public.withdraw_festival_application(p_application_id uuid, p_reason text DEFAULT NULL, p_idempotency_key text DEFAULT NULL) RETURNS public.festival_applications LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE v public.festival_applications%ROWTYPE; old text; BEGIN SELECT * INTO v FROM public.festival_applications WHERE id=p_application_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'Application not found'; END IF; IF NOT public.is_active_band_member(v.band_id) THEN RAISE EXCEPTION 'Not authorised'; END IF; IF EXISTS (SELECT 1 FROM public.festival_contracts c WHERE c.application_id=v.id AND c.status='active') THEN RAISE EXCEPTION 'Cannot withdraw after active contract'; END IF; IF v.status NOT IN ('submitted','under_review','waitlisted','shortlisted','offer_pending') THEN RAISE EXCEPTION 'Application cannot be withdrawn'; END IF; old:=v.status::text; UPDATE public.festival_applications SET status='withdrawn', withdrawal_reason=coalesce(p_reason,'withdrawn'), updated_at=now() WHERE id=v.id RETURNING * INTO v; INSERT INTO public.festival_application_events(application_id,from_state,to_state,actor_profile_id,reason,idempotency_key) VALUES(v.id,old,'withdrawn',public.current_profile_id_safe(),p_reason,p_idempotency_key); RETURN v; END $$;

CREATE OR REPLACE FUNCTION public.create_festival_offer(p_edition_id uuid, p_band_id uuid, p_application_id uuid DEFAULT NULL, p_terms jsonb DEFAULT '{}', p_idempotency_key text DEFAULT NULL) RETURNS public.festival_contract_offers LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE e public.festival_editions%ROWTYPE; o public.festival_contract_offers%ROWTYPE; h text:=public.festival_terms_hash(p_terms); actor uuid:=public.current_profile_id_safe(); slot uuid:=(p_terms->>'stage_slot_id')::uuid; BEGIN SELECT * INTO e FROM public.festival_editions WHERE id=p_edition_id; IF NOT FOUND OR NOT public.can_manage_festival_brand(e.festival_id) THEN RAISE EXCEPTION 'Not authorised to create festival offer'; END IF; IF EXISTS (SELECT 1 FROM public.festival_contracts WHERE edition_id=p_edition_id AND band_id=p_band_id AND status IN ('awaiting_signatures','active','amendment_required')) THEN RAISE EXCEPTION 'Active festival contract already exists'; END IF; IF slot IS NOT NULL AND EXISTS (SELECT 1 FROM public.festival_contracts WHERE stage_slot_id=slot AND status IN ('awaiting_signatures','active')) THEN RAISE EXCEPTION 'Stage slot already reserved'; END IF; IF p_idempotency_key IS NOT NULL THEN SELECT * INTO o FROM public.festival_contract_offers WHERE created_by_profile_id=actor AND idempotency_key=p_idempotency_key; IF FOUND THEN IF o.request_hash<>h THEN RAISE EXCEPTION 'Idempotency key reused with different offer'; END IF; RETURN o; END IF; END IF; INSERT INTO public.festival_contract_offers(edition_id,application_id,band_id,created_by_profile_id,stage_slot_id,proposed_stage_name,proposed_slot_type,proposed_start_at,proposed_end_at,guarantee_fee_cents,deposit_cents,performance_bonus_cents,set_duration_minutes,currency_code,message,expires_at,idempotency_key,request_hash) VALUES(p_edition_id,p_application_id,p_band_id,actor,slot,p_terms->>'proposed_stage_name',p_terms->>'proposed_slot_type',(p_terms->>'proposed_start_at')::timestamptz,(p_terms->>'proposed_end_at')::timestamptz,coalesce((p_terms->>'guarantee_fee_cents')::bigint,0),coalesce((p_terms->>'deposit_cents')::bigint,0),coalesce((p_terms->>'performance_bonus_cents')::bigint,0),(p_terms->>'set_duration_minutes')::integer,coalesce(p_terms->>'currency_code','USD'),p_terms->>'message',(p_terms->>'expires_at')::timestamptz,p_idempotency_key,h) RETURNING * INTO o; INSERT INTO public.festival_offer_revisions(offer_id,revision_number,proposed_by_side,proposed_by_profile_id,terms_snapshot,request_hash,idempotency_key) VALUES(o.id,1,'organiser',actor,p_terms,h,p_idempotency_key); IF p_application_id IS NOT NULL THEN UPDATE public.festival_applications SET status='offer_pending' WHERE id=p_application_id; END IF; RETURN o; END $$;

CREATE OR REPLACE FUNCTION public.review_festival_application(p_application_id uuid, p_action text, p_reason text DEFAULT NULL, p_offer_terms jsonb DEFAULT NULL, p_idempotency_key text DEFAULT NULL) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE a public.festival_applications%ROWTYPE; e public.festival_editions%ROWTYPE; old text; o public.festival_contract_offers%ROWTYPE; ns public.festival_application_status; BEGIN SELECT * INTO a FROM public.festival_applications WHERE id=p_application_id FOR UPDATE; SELECT * INTO e FROM public.festival_editions WHERE id=a.edition_id; IF NOT public.can_manage_festival_brand(e.festival_id) THEN RAISE EXCEPTION 'Not authorised to review application'; END IF; old:=a.status::text; ns := CASE p_action WHEN 'move_to_review' THEN 'under_review' WHEN 'shortlist' THEN 'shortlisted' WHEN 'waitlist' THEN 'waitlisted' WHEN 'reject' THEN 'rejected' WHEN 'create_offer' THEN 'offer_pending' ELSE NULL END; IF ns IS NULL THEN RAISE EXCEPTION 'Unsupported review action'; END IF; UPDATE public.festival_applications SET status=ns, reviewed_at=now(), rejection_reason=CASE WHEN ns='rejected' THEN p_reason ELSE rejection_reason END WHERE id=a.id RETURNING * INTO a; INSERT INTO public.festival_application_events(application_id,from_state,to_state,actor_profile_id,reason,idempotency_key) VALUES(a.id,old,ns::text,public.current_profile_id_safe(),p_reason,p_idempotency_key); IF p_action='create_offer' THEN o:=public.create_festival_offer(a.edition_id,a.band_id,a.id,coalesce(p_offer_terms,'{}'),p_idempotency_key); END IF; RETURN jsonb_build_object('application',to_jsonb(a),'offer',to_jsonb(o)); END $$;

CREATE OR REPLACE FUNCTION public.counter_festival_offer(p_offer_id uuid, p_expected_revision integer, p_terms jsonb, p_change_summary text DEFAULT NULL, p_idempotency_key text DEFAULT NULL) RETURNS public.festival_contract_offers LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE o public.festival_contract_offers%ROWTYPE; e public.festival_editions%ROWTYPE; side public.festival_booking_side; h text:=public.festival_terms_hash(p_terms); existing public.festival_offer_revisions%ROWTYPE; BEGIN SELECT * INTO o FROM public.festival_contract_offers WHERE id=p_offer_id FOR UPDATE; IF NOT FOUND OR o.status IN ('declined','withdrawn','expired','converted_to_contract') THEN RAISE EXCEPTION 'Offer is not negotiable'; END IF; IF o.expires_at IS NOT NULL AND o.expires_at < now() THEN RAISE EXCEPTION 'Offer expired'; END IF; SELECT * INTO e FROM public.festival_editions WHERE id=o.edition_id; IF public.can_manage_festival_brand(e.festival_id) THEN side:='organiser'; ELSIF public.is_active_band_member(o.band_id) THEN side:='band'; ELSE RAISE EXCEPTION 'Not authorised to counter offer'; END IF; IF o.offer_revision <> p_expected_revision THEN RAISE EXCEPTION 'Stale offer revision'; END IF; IF p_idempotency_key IS NOT NULL THEN SELECT * INTO existing FROM public.festival_offer_revisions WHERE offer_id=o.id AND idempotency_key=p_idempotency_key; IF FOUND THEN IF existing.request_hash<>h THEN RAISE EXCEPTION 'Idempotency key reused with different counter'; END IF; RETURN o; END IF; END IF; INSERT INTO public.festival_offer_revisions(offer_id,revision_number,proposed_by_side,proposed_by_profile_id,terms_snapshot,change_summary,request_hash,idempotency_key) VALUES(o.id,o.offer_revision+1,side,public.current_profile_id_safe(),p_terms,p_change_summary,h,p_idempotency_key); UPDATE public.festival_contract_offers SET offer_revision=offer_revision+1,status='countered',updated_at=now() WHERE id=o.id RETURNING * INTO o; RETURN o; END $$;

CREATE OR REPLACE FUNCTION public.accept_festival_offer(p_offer_id uuid, p_revision_number integer, p_idempotency_key text DEFAULT NULL) RETURNS public.festival_contracts LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE o public.festival_contract_offers%ROWTYPE; r public.festival_offer_revisions%ROWTYPE; e public.festival_editions%ROWTYPE; c public.festival_contracts%ROWTYPE; BEGIN SELECT * INTO o FROM public.festival_contract_offers WHERE id=p_offer_id FOR UPDATE; IF NOT FOUND OR o.offer_revision<>p_revision_number THEN RAISE EXCEPTION 'Offer revision is not current'; END IF; SELECT * INTO r FROM public.festival_offer_revisions WHERE offer_id=o.id AND revision_number=p_revision_number; SELECT * INTO e FROM public.festival_editions WHERE id=o.edition_id; IF NOT (public.is_active_band_member(o.band_id) OR public.can_manage_festival_brand(e.festival_id)) THEN RAISE EXCEPTION 'Not authorised to accept offer'; END IF; INSERT INTO public.festival_contracts(edition_id,application_id,offer_id,accepted_offer_revision_id,band_id,festival_id,stage_slot_id,status,terms_snapshot) VALUES(o.edition_id,o.application_id,o.id,r.id,o.band_id,e.festival_id,o.stage_slot_id,'awaiting_signatures',r.terms_snapshot) RETURNING * INTO c; UPDATE public.festival_contract_offers SET status='accepted_pending_contract',responded_at=now() WHERE id=o.id; INSERT INTO public.festival_contract_events(contract_id,offer_id,to_state,actor_profile_id,idempotency_key,metadata) VALUES(c.id,o.id,c.status::text,public.current_profile_id_safe(),p_idempotency_key,jsonb_build_object('accepted_revision',p_revision_number)); RETURN c; END $$;

CREATE OR REPLACE FUNCTION public.decline_festival_offer(p_offer_id uuid, p_reason text DEFAULT NULL, p_idempotency_key text DEFAULT NULL) RETURNS public.festival_contract_offers LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE o public.festival_contract_offers%ROWTYPE; BEGIN SELECT * INTO o FROM public.festival_contract_offers WHERE id=p_offer_id FOR UPDATE; IF NOT (public.is_active_band_member(o.band_id) OR public.can_manage_festival_brand((SELECT edition.festival_id FROM public.festival_editions edition WHERE edition.id=o.edition_id))) THEN RAISE EXCEPTION 'Not authorised'; END IF; UPDATE public.festival_contract_offers SET status='declined',responded_at=now() WHERE id=o.id RETURNING * INTO o; INSERT INTO public.festival_contract_events(offer_id,to_state,actor_profile_id,reason,idempotency_key) VALUES(o.id,'declined',public.current_profile_id_safe(),p_reason,p_idempotency_key); RETURN o; END $$;

CREATE OR REPLACE FUNCTION public.sign_festival_contract(p_contract_id uuid, p_expected_contract_version integer, p_signing_side public.festival_booking_side, p_acknowledgement jsonb DEFAULT '{}', p_idempotency_key text DEFAULT NULL) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE c public.festival_contracts%ROWTYPE; e public.festival_editions%ROWTYPE; h text; s public.festival_contract_signatures%ROWTYPE; actor uuid:=public.current_profile_id_safe(); BEGIN SELECT * INTO c FROM public.festival_contracts WHERE id=p_contract_id FOR UPDATE; IF NOT FOUND OR c.contract_version<>p_expected_contract_version THEN RAISE EXCEPTION 'Contract version mismatch'; END IF; SELECT * INTO e FROM public.festival_editions WHERE id=c.edition_id; IF (p_signing_side='band' AND NOT public.is_active_band_member(c.band_id)) OR (p_signing_side='organiser' AND NOT public.can_manage_festival_brand(e.festival_id)) THEN RAISE EXCEPTION 'Not authorised to sign contract'; END IF; h:=public.festival_terms_hash(c.terms_snapshot); IF p_idempotency_key IS NOT NULL THEN SELECT * INTO s FROM public.festival_contract_signatures WHERE contract_id=c.id AND signing_side=p_signing_side AND idempotency_key=p_idempotency_key; IF FOUND THEN IF s.terms_hash<>h OR s.contract_version<>c.contract_version THEN RAISE EXCEPTION 'Idempotency key reused with different signature'; END IF; RETURN jsonb_build_object('contract',to_jsonb(c),'signature',to_jsonb(s)); END IF; END IF; INSERT INTO public.festival_contract_signatures(contract_id,contract_version,signing_side,profile_id,terms_hash,acknowledgement_snapshot,idempotency_key) VALUES(c.id,c.contract_version,p_signing_side,actor,h,p_acknowledgement,p_idempotency_key) RETURNING * INTO s; UPDATE public.festival_contracts SET band_signature_status=CASE WHEN p_signing_side='band' THEN 'signed' ELSE band_signature_status END, organiser_signature_status=CASE WHEN p_signing_side='organiser' THEN 'signed' ELSE organiser_signature_status END, band_signed_by_profile_id=CASE WHEN p_signing_side='band' THEN actor ELSE band_signed_by_profile_id END, organiser_signed_by_profile_id=CASE WHEN p_signing_side='organiser' THEN actor ELSE organiser_signed_by_profile_id END, band_signed_at=CASE WHEN p_signing_side='band' THEN s.signed_at ELSE band_signed_at END, organiser_signed_at=CASE WHEN p_signing_side='organiser' THEN s.signed_at ELSE organiser_signed_at END WHERE id=c.id RETURNING * INTO c; IF c.band_signature_status='signed' AND c.organiser_signature_status='signed' AND c.status<>'active' THEN UPDATE public.festival_contracts SET status='active',activated_at=now() WHERE id=c.id RETURNING * INTO c; UPDATE public.festival_contract_offers SET status='converted_to_contract' WHERE id=c.offer_id; UPDATE public.festival_applications SET status='converted_to_contract' WHERE id=c.application_id; UPDATE public.festival_stage_slots SET status='confirmed',band_id=c.band_id,canonical_contract_id=c.id WHERE id=c.stage_slot_id AND canonical_contract_id IS NULL; END IF; INSERT INTO public.festival_contract_events(contract_id,from_state,to_state,actor_profile_id,idempotency_key) VALUES(c.id,NULL,c.status::text,actor,p_idempotency_key); RETURN jsonb_build_object('contract',to_jsonb(c),'signature',to_jsonb(s)); END $$;

CREATE OR REPLACE FUNCTION public.amend_festival_contract(p_contract_id uuid, p_terms jsonb, p_reason text, p_idempotency_key text DEFAULT NULL) RETURNS public.festival_contracts LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE c public.festival_contracts%ROWTYPE; e public.festival_editions%ROWTYPE; BEGIN SELECT * INTO c FROM public.festival_contracts WHERE id=p_contract_id FOR UPDATE; SELECT * INTO e FROM public.festival_editions WHERE id=c.edition_id; IF NOT (public.is_active_band_member(c.band_id) OR public.can_manage_festival_brand(e.festival_id)) THEN RAISE EXCEPTION 'Not authorised'; END IF; UPDATE public.festival_contracts SET contract_version=contract_version+1,terms_snapshot=p_terms,status='awaiting_signatures',band_signature_status='unsigned',organiser_signature_status='unsigned',updated_at=now() WHERE id=c.id RETURNING * INTO c; INSERT INTO public.festival_contract_events(contract_id,to_state,actor_profile_id,reason,idempotency_key) VALUES(c.id,c.status::text,public.current_profile_id_safe(),p_reason,p_idempotency_key); RETURN c; END $$;

CREATE OR REPLACE FUNCTION public.cancel_festival_contract(p_contract_id uuid, p_reason text, p_idempotency_key text DEFAULT NULL) RETURNS public.festival_contracts LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE c public.festival_contracts%ROWTYPE; e public.festival_editions%ROWTYPE; BEGIN IF nullif(btrim(p_reason),'') IS NULL THEN RAISE EXCEPTION 'Cancellation reason is required'; END IF; SELECT * INTO c FROM public.festival_contracts WHERE id=p_contract_id FOR UPDATE; SELECT * INTO e FROM public.festival_editions WHERE id=c.edition_id; IF NOT (public.is_active_band_member(c.band_id) OR public.can_manage_festival_brand(e.festival_id)) THEN RAISE EXCEPTION 'Not authorised'; END IF; UPDATE public.festival_contracts SET status='cancelled',cancelled_at=now(),cancellation_reason=p_reason WHERE id=c.id RETURNING * INTO c; UPDATE public.festival_stage_slots SET canonical_contract_id=NULL,status='open' WHERE canonical_contract_id=c.id; INSERT INTO public.festival_contract_events(contract_id,to_state,actor_profile_id,reason,idempotency_key) VALUES(c.id,'cancelled',public.current_profile_id_safe(),p_reason,p_idempotency_key); RETURN c; END $$;

CREATE OR REPLACE FUNCTION public.save_festival_setlist_draft(p_contract_id uuid, p_expected_version integer, p_items jsonb, p_idempotency_key text DEFAULT NULL) RETURNS public.festival_contract_setlists LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE c public.festival_contracts%ROWTYPE; sl public.festival_contract_setlists%ROWTYPE; total integer; maxsec integer; item jsonb; pos integer:=0; BEGIN SELECT * INTO c FROM public.festival_contracts WHERE id=p_contract_id; IF NOT FOUND OR c.status<>'active' THEN RAISE EXCEPTION 'Active contract required'; END IF; IF NOT public.is_active_band_member(c.band_id) THEN RAISE EXCEPTION 'Not authorised to edit setlist'; END IF; maxsec:=coalesce((c.terms_snapshot->>'set_duration_minutes')::integer,60)*60; SELECT * INTO sl FROM public.festival_contract_setlists WHERE contract_id=c.id ORDER BY version DESC LIMIT 1 FOR UPDATE; IF FOUND AND sl.status='locked' THEN RAISE EXCEPTION 'Locked setlist cannot be edited'; END IF; IF FOUND AND sl.version<>p_expected_version THEN RAISE EXCEPTION 'Setlist version mismatch'; END IF; SELECT coalesce(sum((value->>'planned_duration_seconds')::integer),0) INTO total FROM jsonb_array_elements(coalesce(p_items,'[]')); IF total > maxsec OR total < 60 THEN RAISE EXCEPTION 'Setlist duration outside contracted bounds'; END IF; IF NOT FOUND THEN INSERT INTO public.festival_contract_setlists(contract_id,band_id,edition_id,version,total_duration_seconds,maximum_duration_seconds,idempotency_key) VALUES(c.id,c.band_id,c.edition_id,1,total,maxsec,p_idempotency_key) RETURNING * INTO sl; ELSE UPDATE public.festival_contract_setlists SET total_duration_seconds=total,maximum_duration_seconds=maxsec,status='draft',updated_at=now(),version=version+1 WHERE id=sl.id RETURNING * INTO sl; DELETE FROM public.festival_contract_setlist_items WHERE setlist_id=sl.id; END IF; FOR item IN SELECT value FROM jsonb_array_elements(coalesce(p_items,'[]')) LOOP pos:=pos+1; INSERT INTO public.festival_contract_setlist_items(setlist_id,position,song_id,planned_duration_seconds,performance_notes,transition_notes,is_encore) VALUES(sl.id,pos,(item->>'song_id')::uuid,(item->>'planned_duration_seconds')::integer,item->>'performance_notes',item->>'transition_notes',coalesce((item->>'is_encore')::boolean,false)); END LOOP; RETURN sl; END $$;

CREATE OR REPLACE FUNCTION public.submit_festival_setlist(p_setlist_id uuid) RETURNS public.festival_contract_setlists LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE sl public.festival_contract_setlists%ROWTYPE; BEGIN SELECT * INTO sl FROM public.festival_contract_setlists WHERE id=p_setlist_id FOR UPDATE; IF NOT public.is_active_band_member(sl.band_id) THEN RAISE EXCEPTION 'Not authorised'; END IF; IF sl.total_duration_seconds > sl.maximum_duration_seconds THEN RAISE EXCEPTION 'Setlist too long'; END IF; UPDATE public.festival_contract_setlists SET status='submitted',submitted_by_profile_id=public.current_profile_id_safe(),submitted_at=now() WHERE id=sl.id RETURNING * INTO sl; RETURN sl; END $$;

CREATE OR REPLACE FUNCTION public.review_festival_setlist(p_setlist_id uuid, p_action text, p_reason text DEFAULT NULL) RETURNS public.festival_contract_setlists LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE sl public.festival_contract_setlists%ROWTYPE; e public.festival_editions%ROWTYPE; BEGIN SELECT * INTO sl FROM public.festival_contract_setlists WHERE id=p_setlist_id FOR UPDATE; SELECT * INTO e FROM public.festival_editions WHERE id=sl.edition_id; IF NOT public.can_manage_festival_brand(e.festival_id) THEN RAISE EXCEPTION 'Not authorised'; END IF; UPDATE public.festival_contract_setlists SET status=CASE WHEN p_action='approve' THEN 'approved'::public.festival_setlist_status WHEN p_action='request_changes' THEN 'changes_requested'::public.festival_setlist_status ELSE status END, approved_at=CASE WHEN p_action='approve' THEN now() ELSE approved_at END, changes_requested_reason=CASE WHEN p_action='request_changes' THEN p_reason ELSE changes_requested_reason END WHERE id=sl.id RETURNING * INTO sl; RETURN sl; END $$;

CREATE OR REPLACE FUNCTION public.lock_festival_setlist(p_setlist_id uuid) RETURNS public.festival_contract_setlists LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ DECLARE sl public.festival_contract_setlists%ROWTYPE; e public.festival_editions%ROWTYPE; BEGIN SELECT * INTO sl FROM public.festival_contract_setlists WHERE id=p_setlist_id FOR UPDATE; SELECT * INTO e FROM public.festival_editions WHERE id=sl.edition_id; IF NOT public.can_manage_festival_brand(e.festival_id) THEN RAISE EXCEPTION 'Not authorised'; END IF; IF NOT EXISTS (SELECT 1 FROM public.festival_contracts c WHERE c.id=sl.contract_id AND c.status='active') THEN RAISE EXCEPTION 'Active contract required'; END IF; UPDATE public.festival_contract_setlists SET status='locked',locked_at=now() WHERE id=sl.id RETURNING * INTO sl; RETURN sl; END $$;

CREATE OR REPLACE VIEW public.public_festival_lineup AS SELECT c.edition_id,c.band_id,coalesce(c.terms_snapshot->>'proposed_stage_name','TBA') AS stage_display_name, (c.terms_snapshot->>'proposed_start_at')::timestamptz AS start_at, (c.terms_snapshot->>'proposed_end_at')::timestamptz AS end_at, c.terms_snapshot->>'proposed_slot_type' AS slot_type, coalesce((c.terms_snapshot->>'headline')::boolean,false) AS headline, c.status::text AS public_status FROM public.festival_contracts c WHERE c.status='active';
GRANT SELECT ON public.public_festival_lineup TO anon, authenticated;

ALTER TABLE public.festival_applications ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.festival_contract_offers ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.festival_offer_revisions ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.festival_contracts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.festival_contract_signatures ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.festival_contract_setlists ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.festival_contract_setlist_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.festival_application_events ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.festival_contract_events ENABLE ROW LEVEL SECURITY;

CREATE POLICY festival_applications_band_or_owner_read ON public.festival_applications FOR SELECT TO authenticated USING (public.is_active_band_member(band_id) OR EXISTS (SELECT 1 FROM public.festival_editions e WHERE e.id=edition_id AND public.can_manage_festival_brand(e.festival_id)));
CREATE POLICY festival_offers_band_or_owner_read ON public.festival_contract_offers FOR SELECT TO authenticated USING (public.is_active_band_member(band_id) OR EXISTS (SELECT 1 FROM public.festival_editions e WHERE e.id=edition_id AND public.can_manage_festival_brand(e.festival_id)));
CREATE POLICY festival_contracts_band_or_owner_read ON public.festival_contracts FOR SELECT TO authenticated USING (public.is_active_band_member(band_id) OR EXISTS (SELECT 1 FROM public.festival_editions e WHERE e.id=edition_id AND public.can_manage_festival_brand(e.festival_id)));
CREATE POLICY festival_setlists_band_or_owner_read ON public.festival_contract_setlists FOR SELECT TO authenticated USING (public.is_active_band_member(band_id) OR EXISTS (SELECT 1 FROM public.festival_editions e WHERE e.id=edition_id AND public.can_manage_festival_brand(e.festival_id)));
CREATE POLICY festival_setlist_items_parent_read ON public.festival_contract_setlist_items FOR SELECT TO authenticated USING (EXISTS (SELECT 1 FROM public.festival_contract_setlists s WHERE s.id=setlist_id AND (public.is_active_band_member(s.band_id) OR EXISTS (SELECT 1 FROM public.festival_editions e WHERE e.id=s.edition_id AND public.can_manage_festival_brand(e.festival_id)))));
CREATE POLICY festival_offer_revisions_private_read ON public.festival_offer_revisions FOR SELECT TO authenticated USING (EXISTS (SELECT 1 FROM public.festival_contract_offers o WHERE o.id=offer_id AND (public.is_active_band_member(o.band_id) OR EXISTS (SELECT 1 FROM public.festival_editions e WHERE e.id=o.edition_id AND public.can_manage_festival_brand(e.festival_id)))));
CREATE POLICY festival_signatures_private_read ON public.festival_contract_signatures FOR SELECT TO authenticated USING (EXISTS (SELECT 1 FROM public.festival_contracts c WHERE c.id=contract_id AND (public.is_active_band_member(c.band_id) OR EXISTS (SELECT 1 FROM public.festival_editions e WHERE e.id=c.edition_id AND public.can_manage_festival_brand(e.festival_id)))));
CREATE POLICY festival_application_events_private_read ON public.festival_application_events FOR SELECT TO authenticated USING (EXISTS (SELECT 1 FROM public.festival_applications a WHERE a.id=application_id AND (public.is_active_band_member(a.band_id) OR EXISTS (SELECT 1 FROM public.festival_editions e WHERE e.id=a.edition_id AND public.can_manage_festival_brand(e.festival_id)))));
CREATE POLICY festival_contract_events_private_read ON public.festival_contract_events FOR SELECT TO authenticated USING (EXISTS (SELECT 1 FROM public.festival_contracts c WHERE c.id=contract_id AND (public.is_active_band_member(c.band_id) OR EXISTS (SELECT 1 FROM public.festival_editions e WHERE e.id=c.edition_id AND public.can_manage_festival_brand(e.festival_id)))) OR EXISTS (SELECT 1 FROM public.festival_contract_offers o WHERE o.id=offer_id AND (public.is_active_band_member(o.band_id) OR EXISTS (SELECT 1 FROM public.festival_editions e WHERE e.id=o.edition_id AND public.can_manage_festival_brand(e.festival_id)))));

GRANT EXECUTE ON FUNCTION public.submit_festival_application(uuid,uuid,jsonb,text), public.withdraw_festival_application(uuid,text,text), public.review_festival_application(uuid,text,text,jsonb,text), public.create_festival_offer(uuid,uuid,uuid,jsonb,text), public.counter_festival_offer(uuid,integer,jsonb,text,text), public.accept_festival_offer(uuid,integer,text), public.decline_festival_offer(uuid,text,text), public.sign_festival_contract(uuid,integer,public.festival_booking_side,jsonb,text), public.amend_festival_contract(uuid,jsonb,text,text), public.cancel_festival_contract(uuid,text,text), public.save_festival_setlist_draft(uuid,integer,jsonb,text), public.submit_festival_setlist(uuid), public.review_festival_setlist(uuid,text,text), public.lock_festival_setlist(uuid) TO authenticated;